sql:
SELECT dog_name
FROM dogs
WHERE dog_stage = 'doggo';

SELECT dog_name, dog_breed
FROM dogs
ORDER BY age DESC;

SELECT dog_name 
FROM tweets 
WHERE rating_numerator = (SELECT MAX(rating_numerator) FROM tweets);

SELECT DISTINCT d.dog_stage
FROM tweets t
INNER JOIN dogs d ON t.dog_name = d.dog_name;

SELECT dog_name 
FROM tweets 
WHERE tweet_id = 1;

SELECT tweet_id, COUNT(tweet_id) AS total_tweets
FROM tweets
GROUP BY tweet_id;

SELECT DISTINCT dog_name
FROM tweets
WHERE rating_numerator IS NOT NULL AND rating_denominator IS NOT NULL;

SELECT COUNT(tweet_id) 
FROM tweets 
WHERE text LIKE '%puppy%';

SELECT dog_name, rating_numerator, rating_denominator
FROM tweets
ORDER BY rating_numerator DESC;
